class Solution {
    public int countWinningSequences(String s) {
        int n = s.length();
        int mod = 1000000007;
        long[] dp = new long[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; i++) {
            if (s.charAt(i - 1) == 'F') {
                dp[i] = (dp[i - 1] + dp[i - 2]) % mod;
            } else if (s.charAt(i - 1) == 'W') {
                dp[i] = (dp[i - 1] + dp[i - 2]) % mod;
            } else {
                dp[i] = (dp[i - 1] + dp[i - 3]) % mod;
            }
        }
        long ans = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == 'F') {
                ans = (ans + dp[n - 1] - dp[i]) % mod;
            } else if (s.charAt(i) == 'W') {
                ans = (ans + dp[n - 1] - dp[i]) % mod;
            } else {
                ans = (ans + dp[n - 1] - dp[i]) % mod;
            }
        }
        return (int) ans;
    }
}
